class Solution:
    def incremovableSubarrayCount(self, nums):
        n = len(nums)
        def is_incr(arr):
            return all(arr[t] < arr[t + 1] for t in range(len(arr) - 1))
        count = 0
        for i in range(n):
            for j in range(i, n):
                remaining = nums[:i] + nums[j + 1:]
                if is_incr(remaining):
                    count += 1
        return count

