class Solution:
    def incremovableSubarrayCount(self, nums):
        n = len(nums)
        prefix_ok = [False] * (n + 1)
        prefix_ok[0] = True
        if n >= 1:
            prefix_ok[1] = True
        for i in range(2, n + 1):
            prefix_ok[i] = prefix_ok[i - 1] and nums[i - 2] < nums[i - 1]

        suffix_ok = [False] * (n + 1)
        suffix_ok[n] = True
        if n >= 1:
            suffix_ok[n - 1] = True
        for j in range(n - 2, -1, -1):
            suffix_ok[j] = suffix_ok[j + 1] and nums[j] < nums[j + 1]

        count = 0
        for i in range(0, n + 1):
            for j in range(i + 1, n + 1):
                if not prefix_ok[i] or not suffix_ok[j]:
                    continue
                if i == 0 or j == n or nums[i - 1] < nums[j]:
                    count += 1
        return count

