var incremovableSubarrayCount = function(nums) {
    const n = nums.length;
    const prefixOk = new Array(n + 1).fill(false);
    prefixOk[0] = true;
    if (n >= 1) prefixOk[1] = true;
    for (let i = 2; i <= n; i++) prefixOk[i] = prefixOk[i - 1] && nums[i - 2] < nums[i - 1];

    const suffixOk = new Array(n + 1).fill(false);
    suffixOk[n] = true;
    if (n >= 1) suffixOk[n - 1] = true;
    for (let j = n - 2; j >= 0; j--) suffixOk[j] = suffixOk[j + 1] && nums[j] < nums[j + 1];

    let count = 0;
    for (let i = 0; i <= n; i++) {
        for (let j = i + 1; j <= n; j++) {
            if (!prefixOk[i] || !suffixOk[j]) continue;
            if (i === 0 || j === n || nums[i - 1] < nums[j]) count++;
        }
    }
    return count;
};
